const { execSync } = require('child_process');
const dbPath = '/home/n8n/.n8n/job_search.db';

function sqlQuery(sql) {
  try {
    const result = execSync('sqlite3 -json ' + dbPath + ' ' + JSON.stringify(sql), { encoding: 'utf8', timeout: 10000 });
    return result.trim() ? JSON.parse(result) : [];
  } catch(e) {
    console.error('SQLite query error:', e.message);
    return [];
  }
}

const today = new Date().toISOString().split('T')[0];

// Get all pending follow-ups due today or overdue
const dueFollowups = sqlQuery(
  'SELECT f.id, f.application_id, f.due_date, f.type, a.company_name, a.job_title, a.job_url, a.status ' +
  'FROM follow_ups f ' +
  'LEFT JOIN applications a ON f.application_id = a.id ' +
  'WHERE f.status = \'pending\' AND f.due_date <= \'' + today + '\' ' +
  'AND (a.status IS NULL OR a.status NOT IN (\'rejected\', \'withdrawn\', \'accepted\')) ' +
  'ORDER BY f.due_date ASC ' +
  'LIMIT 20'
);

console.log('Due follow-ups found: ' + dueFollowups.length);

if (dueFollowups.length === 0) {
  return [{ json: { status: 'no_followups', count: 0, today: today } }];
}

return dueFollowups.map(function(f) {
  return { json: {
    followup_id: f.id,
    application_id: f.application_id,
    company_name: f.company_name || 'Unknown',
    job_title: f.job_title || 'Unknown',
    job_url: f.job_url || '',
    due_date: f.due_date,
    followup_type: f.type,
    app_status: f.status || 'applied',
    today: today
  }};
});

const data = $input.item.json;

const followupNumber = data.followup_type === 'follow_up_1' ? '1' :
  data.followup_type === 'follow_up_2' ? '2' : '3';

const subject = 'Following up — ' + data.job_title + ' at ' + data.company_name;

let emailBody = '';
if (followupNumber === '1') {
  emailBody = 'Hi Hiring Team,\n\n' +
    'I wanted to follow up on my application for the ' + data.job_title + ' position at ' + data.company_name + '.\n\n' +
    'I remain very excited about this opportunity and would love to discuss how my experience can contribute to your team.\n\n' +
    'Would you be available for a brief call this week?\n\n' +
    'Best regards,\n[YOUR NAME]';
} else if (followupNumber === '2') {
  emailBody = 'Hi Hiring Team,\n\n' +
    'I am writing to check in on my application for ' + data.job_title + ' at ' + data.company_name + '.\n\n' +
    'I continue to be impressed by ' + data.company_name + '\'s work and remain very interested in contributing.\n\n' +
    'Please let me know if there is any additional information I can provide.\n\n' +
    'Best regards,\n[YOUR NAME]';
} else {
  emailBody = 'Hi Hiring Team,\n\n' +
    'I wanted to send a final note regarding the ' + data.job_title + ' position at ' + data.company_name + '.\n\n' +
    'I understand if the timing is not right, and I would welcome the opportunity to be considered for future roles.\n\n' +
    'Thank you for your time and consideration.\n\n' +
    'Best regards,\n[YOUR NAME]';
}

return [{
  json: {
    ...data,
    followup_number: followupNumber,
    draft_subject: subject,
    draft_body: emailBody
  }
}];

